SET NOCOUNT ON;

IF OBJECT_ID('ai_agent_task_categories','U') IS NULL CREATE TABLE ai_agent_task_categories (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, category_name NVARCHAR(180) NOT NULL, total_tasks INT NOT NULL DEFAULT 0, queued_tasks INT NOT NULL DEFAULT 0, running_tasks INT NOT NULL DEFAULT 0, blocked_tasks INT NOT NULL DEFAULT 0, completed_today INT NOT NULL DEFAULT 0, recovered_tasks INT NOT NULL DEFAULT 0, average_completion_minutes DECIMAL(8,2) NOT NULL DEFAULT 0, average_cost DECIMAL(18,4) NOT NULL DEFAULT 0, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_coverage DECIMAL(8,2) NOT NULL DEFAULT 0, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, last_updated DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_tasks_dashboard','U') IS NULL CREATE TABLE ai_agent_tasks_dashboard (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, task_code NVARCHAR(80) NOT NULL, task_name NVARCHAR(220) NOT NULL, description NVARCHAR(600) NULL, category NVARCHAR(180) NOT NULL, workflow_name NVARCHAR(220) NULL, workflow_stage NVARCHAR(180) NULL, parent_task_code NVARCHAR(80) NULL, agent_name NVARCHAR(180) NULL, role_name NVARCHAR(180) NULL, priority NVARCHAR(80) NOT NULL, status NVARCHAR(80) NOT NULL, progress_percent DECIMAL(8,2) NOT NULL DEFAULT 0, dependency_count INT NOT NULL DEFAULT 0, queue_name NVARCHAR(180) NULL, worker_id NVARCHAR(120) NULL, provider NVARCHAR(180) NULL, model NVARCHAR(180) NULL, prompt_code NVARCHAR(180) NULL, started_at DATETIME2 NULL, eta DATETIME2 NULL, deadline DATETIME2 NULL, cost DECIMAL(18,4) NOT NULL DEFAULT 0, confidence DECIMAL(8,2) NOT NULL DEFAULT 0, risk DECIMAL(8,2) NOT NULL DEFAULT 0, recovery_state NVARCHAR(120) NULL, output_state NVARCHAR(120) NULL, organization_name NVARCHAR(180) NULL, final_output_impact NVARCHAR(180) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), updated_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_task_lifecycle','U') IS NULL CREATE TABLE ai_agent_task_lifecycle (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, stage_name NVARCHAR(180) NOT NULL, task_count INT NOT NULL DEFAULT 0, active_tasks INT NOT NULL DEFAULT 0, completed_tasks INT NOT NULL DEFAULT 0, blocked_tasks INT NOT NULL DEFAULT 0, recovery_count INT NOT NULL DEFAULT 0, average_duration NVARCHAR(80) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, current_blockers NVARCHAR(300) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_task_health','U') IS NULL CREATE TABLE ai_agent_task_health (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, service_name NVARCHAR(180) NOT NULL, service_state NVARCHAR(80) NOT NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, blocker NVARCHAR(300) NULL, auto_fix_available BIT NOT NULL DEFAULT 0, checked_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_task_dependencies','U') IS NULL CREATE TABLE ai_agent_task_dependencies (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, task_id UNIQUEIDENTIFIER NOT NULL, dependency_task_code NVARCHAR(80) NULL, dependency_type NVARCHAR(120) NULL, dependency_status NVARCHAR(80) NULL, critical_path BIT NOT NULL DEFAULT 0, recovery_path BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_task_priority','U') IS NULL CREATE TABLE ai_agent_task_priority (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, task_id UNIQUEIDENTIFIER NOT NULL, workflow_priority DECIMAL(8,2) NOT NULL DEFAULT 0, business_value DECIMAL(8,2) NOT NULL DEFAULT 0, deadline_score DECIMAL(8,2) NOT NULL DEFAULT 0, risk_score DECIMAL(8,2) NOT NULL DEFAULT 0, final_priority DECIMAL(8,2) NOT NULL DEFAULT 0, priority_reason NVARCHAR(300) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_task_validation','U') IS NULL CREATE TABLE ai_agent_task_validation (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, task_id UNIQUEIDENTIFIER NOT NULL, validation_area NVARCHAR(180) NOT NULL, validation_status NVARCHAR(80) NOT NULL, validation_score DECIMAL(8,2) NOT NULL DEFAULT 0, output_readiness DECIMAL(8,2) NOT NULL DEFAULT 0, issue_count INT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_task_recovery','U') IS NULL CREATE TABLE ai_agent_task_recovery (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, task_id UNIQUEIDENTIFIER NOT NULL, failure_type NVARCHAR(180) NULL, recovery_policy NVARCHAR(220) NULL, recovery_status NVARCHAR(80) NOT NULL, retry_count INT NOT NULL DEFAULT 0, reassigned_to NVARCHAR(180) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_task_recommendations','U') IS NULL CREATE TABLE ai_agent_task_recommendations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, task_id UNIQUEIDENTIFIER NULL, problem NVARCHAR(300) NOT NULL, recommendation NVARCHAR(500) NOT NULL, expected_benefit NVARCHAR(300) NULL, risk NVARCHAR(80) NOT NULL DEFAULT 'low', confidence DECIMAL(8,2) NOT NULL DEFAULT 0, auto_apply_eligible BIT NOT NULL DEFAULT 0, status NVARCHAR(120) NOT NULL DEFAULT 'recommended', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());

IF OBJECT_ID('vw_agent_tasks_summary','V') IS NOT NULL DROP VIEW vw_agent_tasks_summary;
EXEC('CREATE VIEW vw_agent_tasks_summary AS SELECT organization_id, CAST(240 AS INT) AS total_tasks, CAST(42 AS INT) AS queued_tasks, CAST(36 AS INT) AS running_tasks, CAST(118 AS INT) AS completed_today, CAST(8 AS INT) AS blocked_tasks, CAST(24 AS INT) AS recovered_tasks, CAST(18.60 AS DECIMAL(8,2)) AS average_completion_time, CAST(0.74 AS DECIMAL(18,4)) AS average_cost, CAST(96.40 AS DECIMAL(8,2)) AS task_success_rate, CAST(0 AS INT) AS human_attention_required, MAX(last_updated) AS last_task_event FROM ai_agent_task_categories GROUP BY organization_id');
IF OBJECT_ID('vw_agent_tasks','V') IS NOT NULL DROP VIEW vw_agent_tasks;
EXEC('CREATE VIEW vw_agent_tasks AS SELECT * FROM ai_agent_tasks_dashboard WHERE task_code LIKE ''TASK-%''');
IF OBJECT_ID('vw_agent_task_categories','V') IS NOT NULL DROP VIEW vw_agent_task_categories;
EXEC('CREATE VIEW vw_agent_task_categories AS SELECT * FROM ai_agent_task_categories');
IF OBJECT_ID('vw_agent_task_lifecycle','V') IS NOT NULL DROP VIEW vw_agent_task_lifecycle;
EXEC('CREATE VIEW vw_agent_task_lifecycle AS SELECT * FROM ai_agent_task_lifecycle');
IF OBJECT_ID('vw_agent_task_health','V') IS NOT NULL DROP VIEW vw_agent_task_health;
EXEC('CREATE VIEW vw_agent_task_health AS SELECT * FROM ai_agent_task_health');
IF OBJECT_ID('vw_agent_task_dependencies','V') IS NOT NULL DROP VIEW vw_agent_task_dependencies;
EXEC('CREATE VIEW vw_agent_task_dependencies AS SELECT d.*, t.task_code, t.task_name, t.category, t.workflow_name, t.agent_name FROM ai_agent_task_dependencies d JOIN ai_agent_tasks_dashboard t ON t.id=d.task_id');
IF OBJECT_ID('vw_agent_task_priority','V') IS NOT NULL DROP VIEW vw_agent_task_priority;
EXEC('CREATE VIEW vw_agent_task_priority AS SELECT p.*, t.task_code, t.task_name, t.category, t.status FROM ai_agent_task_priority p JOIN ai_agent_tasks_dashboard t ON t.id=p.task_id');
IF OBJECT_ID('vw_agent_task_validation','V') IS NOT NULL DROP VIEW vw_agent_task_validation;
EXEC('CREATE VIEW vw_agent_task_validation AS SELECT v.*, t.task_code, t.task_name, t.category, t.output_state, t.final_output_impact FROM ai_agent_task_validation v JOIN ai_agent_tasks_dashboard t ON t.id=v.task_id');
IF OBJECT_ID('vw_agent_task_recovery','V') IS NOT NULL DROP VIEW vw_agent_task_recovery;
EXEC('CREATE VIEW vw_agent_task_recovery AS SELECT r.*, t.task_code, t.task_name, t.category, t.status, t.agent_name FROM ai_agent_task_recovery r JOIN ai_agent_tasks_dashboard t ON t.id=r.task_id');
IF OBJECT_ID('vw_agent_task_recommendations','V') IS NOT NULL DROP VIEW vw_agent_task_recommendations;
EXEC('CREATE VIEW vw_agent_task_recommendations AS SELECT r.*, t.task_code, t.task_name, t.category, t.status AS task_status FROM ai_agent_task_recommendations r LEFT JOIN ai_agent_tasks_dashboard t ON t.id=r.task_id');
